import { Component, Event, EventEmitter, getElement, h, Host, Prop, Watch } from '@stencil/core';
import { customTwMerge, propagateToSlot } from '../../utils/utils';
import { FOCUSABLE_SELECTORS } from '../../models/pseudo-states.model';

@Component({
  tag: 'wdpr-ghost-container',
  shadow: true,
})
export class WdprGhostContainer {
  /**
   * Fired when the container is activated (click, Enter, or Space) while interactive and not disabled.
   */
  @Event({ eventName: 'wdprGhostContainerClick' }) wdprGhostContainerClick!: EventEmitter<void>;

  /**
   * When true, the container itself is focusable and shows hover/pressed/focus states.
   * Use this when the container is an actionable affordance (e.g., clickable drop zone).
   */
  @Prop() interactive = true;

  @Prop() disabled = false;

  @Watch('disabled')
  _handleDisabledChange(): void {
    this._handleSlotChange();
  }

  @Watch('interactive')
  _handleInteractiveChange(): void {
    this._handleSlotChange();
  }

  private get _hostEl(): HTMLWdprGhostContainerElement {
    return getElement(this) as HTMLWdprGhostContainerElement;
  }

  private _getSlotEl(): HTMLSlotElement | null {
    return this._hostEl.shadowRoot?.querySelector('slot') ?? null;
  }

  private _getContainerEl(): HTMLElement | null {
    return (this._hostEl.shadowRoot?.querySelector('[part="container"]') as HTMLElement | null) ?? null;
  }

  private _isContainerFocusable(): boolean {
    return this.interactive && !this.disabled;
  }

  private _getSlottedRoots(slotEl: HTMLSlotElement): Element[] {
    return slotEl
      .assignedNodes({ flatten: true })
      .filter((n): n is Element => n.nodeType === Node.ELEMENT_NODE);
  }

  private _getFocusableElementsWithin(root: Element): Element[] {
    const selector = FOCUSABLE_SELECTORS;
    const found: Element[] = [];

    if (root.matches(selector)) found.push(root);
    root.querySelectorAll(selector).forEach((el) => found.push(el));

    return found;
  }

  private _isElement(node: unknown): node is Element {
    return node instanceof Element;
  }

  private _isEventFromFocusable(event: Event): boolean {
    const path = typeof event.composedPath === 'function' ? event.composedPath() : [];
    
    return path.some((n) => this._isElement(n) && n.matches(FOCUSABLE_SELECTORS));
  }

  private _disableTabOrderForSlottedContent(): void {
    const slotEl = this._getSlotEl();
    if (!slotEl) return;

    const roots = this._getSlottedRoots(slotEl);

    roots.forEach((root) => {
      this._getFocusableElementsWithin(root).forEach((el) => {
        if (!el.hasAttribute('data-wdpr-prev-tabindex')) {
          const prev = el.getAttribute('tabindex');
          el.setAttribute('data-wdpr-prev-tabindex', prev ?? '');
        }

        el.setAttribute('tabindex', '-1');
      });
    });
  }

  private _restoreTabOrderForSlottedContent(): void {
    const slotEl = this._getSlotEl();
    if (!slotEl) return;

    const roots = this._getSlottedRoots(slotEl);

    roots.forEach((root) => {
      const selector = '[data-wdpr-prev-tabindex]';

      if (root.hasAttribute('data-wdpr-prev-tabindex')) {
        const prev = root.getAttribute('data-wdpr-prev-tabindex');
        if (prev === '') root.removeAttribute('tabindex');
        else if (prev != null) root.setAttribute('tabindex', prev);
        root.removeAttribute('data-wdpr-prev-tabindex');
      }

      root.querySelectorAll(selector).forEach((el) => {
        const prev = el.getAttribute('data-wdpr-prev-tabindex');
        if (prev === null) return;

        if (prev === '') el.removeAttribute('tabindex');
        else el.setAttribute('tabindex', prev);

        el.removeAttribute('data-wdpr-prev-tabindex');
      });
    });
  }

  private _onFocusIn = (event: FocusEvent): void => {
  if (!this.interactive || this.disabled) return;

  const container = this._getContainerEl();
  if (!container) return;

  if (event.target !== container) {
    event.stopPropagation();
    queueMicrotask(() => container.focus());
  }
};


  private _syncSlottedInteractivity(): void {
    if (this.disabled || this.interactive) this._disableTabOrderForSlottedContent();
    else this._restoreTabOrderForSlottedContent();
  }

  private _handleSlotChange = (): void => {
  if (this.disabled) propagateToSlot(this._getSlotEl(), 'disabled', true);
    this._syncSlottedInteractivity();
  };



  public componentDidLoad(): void {
    this._handleSlotChange();
  }

  private _emitActivate(): void {
    if (!this._isContainerFocusable()) return;
    this.wdprGhostContainerClick.emit();
  }

  private _onClick = (event: MouseEvent): void => {
    if (!this._isContainerFocusable()) return;

    if (this._isEventFromFocusable(event)) return;

    this._emitActivate();
    event.preventDefault();
  };

  private _onKeyDown = (event: KeyboardEvent): void => {
    if (!this._isContainerFocusable()) return;

    const container = this._getContainerEl();
    if (!container || event.target !== container) return;

    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      this._emitActivate();
    }
  };

  private get _containerClasses(): string {
    const base = customTwMerge(
      'flex justify-center items-center overflow-hidden text-center',
      'rounded-200',
      'bg-surface-white-000-a48',
      'border-025 border-dashed border-stroke-actionable-alt-disabled',
      'p-200 max-w-[388px] min-h-[72px]',
      'outline-none',
      'focus:outline-none',
    );

    const focusRing =
      this.interactive && !this.disabled
        ? customTwMerge(
            'focus-visible:outline',
            'focus-visible:outline-solid',
            'focus-visible:outline-offset-2',
            'focus-visible:outline-stroke-actionable-focused',
            'focus-visible:outline-037',
          )
        : '';

    const interactiveStates =
      this.interactive && !this.disabled
        ? customTwMerge('cursor-pointer', 'hover:border-stroke-actionable-hover', 'active:border-stroke-actionable-focused')
        : '';

    const disabledState = this.disabled ? customTwMerge('border-stroke-disabled') : '';

    return customTwMerge(base, focusRing, interactiveStates, disabledState);
  }

  render() {
    const isFocusable = this._isContainerFocusable();
    const tabindex = isFocusable ? 0 : undefined;

    return (
      <Host>
        <div
          part="container"
          class={this._containerClasses}
          tabindex={tabindex}
          role={this.interactive ? 'button' : null}
          aria-disabled={this.disabled ? 'true' : null}
          onClick={this._onClick}
          onKeyDown={this._onKeyDown}
          onFocusin={this._onFocusIn}
        >
          <div class="w-full">
            <slot onSlotchange={this._handleSlotChange} />
          </div>
        </div>
      </Host>
    );
  }
}
